export interface Tile {
  x: number;
  y: number;
  zone: ZoneType;
  building: Building;
  landValue: number;
  pollution: number;
  crime: number;
  traffic: number;
  hasSubway: boolean;
  hasRailOverlay?: boolean;
}

export interface City {
  id: string;
  name: string;
  bounds: { minX: number; minY: number; maxX: number; maxY: number };
  economy: CityEconomy;
  color: string;
}

export interface AdjacentCity {
  id: string;
  name: string;
  direction: 'north' | 'south' | 'east' | 'west';
  connected: boolean;
  discovered: boolean;
}

export interface WaterBody {
  id: string;
  name: string;
  type: 'lake' | 'ocean';
  tiles: { x: number; y: number }[];
  centerX: number;
  centerY: number;
}

export interface Notification {
  id: string;
  title: string;
  description: string;
  icon: string;
  timestamp: number;
}

export interface AdvisorMessage {
  name: string;
  icon: string;
  messages: string[];
  priority: 'low' | 'medium' | 'high' | 'critical';
}

export interface PortfolioCompanyTile {
  companyId: string;
  name: string;
  x: number;
  y: number;
  kind: 'portfolio' | 'competitor' | 'opportunity';
  size: 'small' | 'medium' | 'large';
  headcount?: number;
}

export interface PendingOpportunity {
  id: string;
  companyId: string;
  name: string;
  kind: 'opportunity' | 'portfolio_round';
  industry?: string;
  stage?: string;
  valuationUsd?: number;
  headcount?: number;
  rivalInvestor?: string;
  openRound: boolean;
  createdAt: number;
}

export interface GameState {
  id: string;
  grid: Tile[][];
  gridSize: number;
  cityName: string;
  year: number;
  month: number;
  day: number;
  hour: number;
  tick: number;
  speed: 0 | 1 | 2 | 3;
  selectedTool: Tool;
  taxRate: number;
  effectiveTaxRate: number;
  competitionDegree: number;
  stats: Stats;
  budget: Budget;
  services: ServiceCoverage;
  notifications: Notification[];
  advisorMessages: AdvisorMessage[];
  history: HistoryPoint[];
  activePanel: 'none' | 'budget' | 'statistics' | 'advisors' | 'settings';
  disastersEnabled: boolean;
  adjacentCities: AdjacentCity[];
  waterBodies: WaterBody[];
  gameVersion: number;
  cities: City[];
  investorProfile?: {
    id: string;
    name: string;
    domain: string;
    march_rank?: number;
    hq?: string;
    founded_year?: number;
    aum_usd?: number;
    follow_on_rate_pct?: number;
    lead_investment_ratio_pct?: number;
    exit_ratio_pct?: number;
  };
  portfolioCompanies?: Array<{
    id: string;
    name: string;
    domain?: string | null;
    sector?: string;
    stage?: string;
    logo_url?: string;
  }>;
  portfolioCompanyTiles?: PortfolioCompanyTile[];
  pendingOpportunities?: PendingOpportunity[];
  llmRouterMode?: string;
}

export interface SavedCityMeta {
  id: string;
  cityName: string;
  population: number;
  money: number;
  year: number;
  month: number;
  gridSize: number;
  savedAt: number;
  roomCode?: string;
}
